trigger.body:
v_mensaje VARCHAR;

BEGIN
select docstatus into v_mensaje from atindpo_postventa where atindpo_postventa_id = :new.atindpo_postventa_id;

		IF(INSERTING)THEN
             if (v_mensaje<>'EP' and v_mensaje<>'EE')then
		raise exception '%', 'La orden de servicio debe estar estado “En proceso”';
             end if;

		RETURN NEW;

		END IF;
END ATINDPO_COMPARAESTADO_TRG
